# verify.jl -- triangulate Phase 5 PadeStepper oracle sources, then
# emit test/_oracle_padestepper.jl.
#
# Sources:
#   oracles_wolfram.txt — Mathematica closed-form ℘ + NDSolve
#                         (two methods inside the same script);
#                         NDSolve also handles PI.
#   oracles_python.txt  — mpmath.odefun at 40 dps for both ODEs.
#
# Usage (from project root):
#   julia --project=. external/probes/padestepper-oracle/verify.jl
# Run AFTER:
#   wolframscript -file external/probes/padestepper-oracle/capture.wl
#   python3 external/probes/padestepper-oracle/capture.py
#
# Asserts agreement to within Float64-vs-Float64 rounding (1e-13 for
# values O(1), 1e-11 for values O(100), 1e-10 for values O(400)).

using Printf

const HERE = @__DIR__
const PROJECT_ROOT = abspath(joinpath(HERE, "..", "..", ".."))
const O_WL = joinpath(HERE, "oracles_wolfram.txt")
const O_PY = joinpath(HERE, "oracles_python.txt")
const PINNED = joinpath(PROJECT_ROOT, "test", "_oracle_padestepper.jl")

module _OWL end
module _OPY end

Base.include_string(_OWL, read(O_WL, String), O_WL)
Base.include_string(_OPY, read(O_PY, String), O_PY)

# ─── Cross-source assertions ──────────────────────────────────────────

function check_agree(label, vals...; rtol)
    a = vals[1]
    for (i, v) in enumerate(vals[2:end])
        rel = abs(a - v) / max(abs(a), abs(v), 1e-300)
        rel < rtol || error("$label: source 1 = $a, source $(i+1) = $v, rel = $rel > rtol = $rtol")
    end
    @printf("%-50s  %.16f  (max rel %.2e)\n", label, a,
            maximum([abs(a - v)/max(abs(a), abs(v), 1e-300) for v in vals[2:end]]))
end

# ---- 5.1.1 ℘ at z=0.5: closed-form ≡ NDSolve ≡ mpmath.odefun ----
check_agree("5.1.1 u  at z=0.5  (℘)",
            _OWL.u_5_1_1_at_05,
            _OWL.u_5_1_1_at_05_via_NDSolve,
            _OPY.u_5_1_1_at_05_py;
            rtol = 1e-13)
check_agree("5.1.1 u' at z=0.5  (℘)",
            _OWL.up_5_1_1_at_05,
            _OWL.up_5_1_1_at_05_via_NDSolve,
            _OPY.up_5_1_1_at_05_py;
            rtol = 1e-13)

# ---- 5.1.2 ℘ at z=0.9: closed-form ≡ mpmath ----
check_agree("5.1.2 u  at z=0.9  (℘ near pole)",
            _OWL.u_5_1_2_at_09,
            _OPY.u_5_1_2_at_09_py;
            rtol = 1e-12)
check_agree("5.1.2 u' at z=0.9  (℘ near pole)",
            _OWL.up_5_1_2_at_09,
            _OPY.up_5_1_2_at_09_py;
            rtol = 1e-12)

# ---- 5.1.3 PI at z=0.5: NDSolve ≡ mpmath.odefun ----
check_agree("5.1.3 u  at z=0.5  (PI)",
            _OWL.u_5_1_3_PI_at_05,
            _OPY.u_5_1_3_PI_at_05_py;
            rtol = 1e-13)
check_agree("5.1.3 u' at z=0.5  (PI)",
            _OWL.up_5_1_3_PI_at_05,
            _OPY.up_5_1_3_PI_at_05_py;
            rtol = 1e-13)

# ---- 5.1.4 ℘ at z=0.95 (near pole): closed-form ≡ mpmath ----
check_agree("5.1.4 u  at z=0.95 (℘ very near pole)",
            _OWL.u_5_1_4_at_095,
            _OPY.u_5_1_4_at_095_py;
            rtol = 1e-11)
check_agree("5.1.4 u' at z=0.95 (℘ very near pole)",
            _OWL.up_5_1_4_at_095,
            _OPY.up_5_1_4_at_095_py;
            rtol = 1e-11)

# Sanity cross-check: PI at z=0.5 differs from ℘ at z=0.5 by O(z²/12),
# i.e. h²/12 = 0.5²/12 ≈ 0.0208 — the first-order contribution of the
# +z RHS term to u(z).  diff_PI_minus_weier_at_05 ≈ 0.0296.
let
    diff = _OWL.diff_PI_minus_weier_at_05
    @assert 0.01 < diff < 0.1 "PI - ℘ at z=0.5 should be in (0.01, 0.1); got $diff"
    @printf("PI - ℘ at z=0.5 = %.4f (expected O(h²/12) ≈ 0.02)\n", diff)
end

println()

# ─── Emit canonical test/_oracle_padestepper.jl ──────────────────────
open(PINNED, "w") do io
    print(io, """
# test/_oracle_padestepper.jl -- Phase 5 oracle, pinned values.
#
# This file is auto-generated by:
#   external/probes/padestepper-oracle/verify.jl
# from two/three independent sources cross-checked to agree at the
# tolerances listed in verify.jl:
#
#   oracles_wolfram.txt — Mathematica closed-form WeierstrassP +
#                         NDSolve at WorkingPrecision=50 (the latter
#                         also handles Painleve I).
#   oracles_python.txt  — mpmath.odefun at 40 dps (Taylor-method
#                         arbitrary-precision ODE solver), for both ODEs.
#
# Do NOT hand-edit. Re-run capture.{wl,py} + verify.jl to update;
# verify.jl asserts agreement before writing.

""")
    print(io, read(O_WL, String))
end

println("Wrote ", PINNED)
